import json
import base64
import os
import tempfile
import hashlib

class Substrato631OpenservGateway:
    def __init__(self):
        self.metadata = {
            "id": "631-OPENSERV-GATEWAY",
            "phi_c": 0.999,
            "architecture": "OpenServ Gateway Sysfs"
        }
        self.gateway_fastapi_b64 = """"""
        self.arkhe_gateway_b64 = """"""
        self.main_rs_b64 = """"""
        self.init_sh_b64 = """"""
        self.sysfs_http_bridge_b64 = """"""
        self.makefile_b64 = """b2JqLW0gKz0gYXJraGVfZ2F0ZXdheS5vCgphbGw6CgltYWtlIC1DIC9saWIvbW9kdWxlcy8kKHNoZWxsIHVuYW1lIC1yKS9idWlsZCBNPSQoUFdEKSBtb2R1bGVzCgpjbGVhbjoKCW1ha2UgLUMgL2xpYi9tb2R1bGVzLyQoc2hlbGwgdW5hbWUgLXIpL2J1aWxkIE09JChQV0QpIGNsZWFuCg=="""

    def generate(self):
        temp_dir = tempfile.mkdtemp()

        with os.fdopen(os.open(os.path.join(temp_dir, "gateway_fastapi.py"), os.O_WRONLY | os.O_CREAT, 0o644), "w") as f:
            f.write(base64.b64decode(self.gateway_fastapi_b64).decode('utf-8'))
        with os.fdopen(os.open(os.path.join(temp_dir, "arkhe_gateway.c"), os.O_WRONLY | os.O_CREAT, 0o644), "w") as f:
            f.write(base64.b64decode(self.arkhe_gateway_b64).decode('utf-8'))
        with os.fdopen(os.open(os.path.join(temp_dir, "main.rs"), os.O_WRONLY | os.O_CREAT, 0o644), "w") as f:
            f.write(base64.b64decode(self.main_rs_b64).decode('utf-8'))
        with os.fdopen(os.open(os.path.join(temp_dir, "init_631.sh"), os.O_WRONLY | os.O_CREAT, 0o755), "w") as f:
            f.write(base64.b64decode(self.init_sh_b64).decode('utf-8'))
        with os.fdopen(os.open(os.path.join(temp_dir, "sysfs_http_bridge.py"), os.O_WRONLY | os.O_CREAT, 0o644), "w") as f:
            f.write(base64.b64decode(self.sysfs_http_bridge_b64).decode('utf-8'))
        with os.fdopen(os.open(os.path.join(temp_dir, "Makefile"), os.O_WRONLY | os.O_CREAT, 0o644), "w") as f:
            f.write(base64.b64decode(self.makefile_b64).decode('utf-8'))

        seal = hashlib.sha3_256(json.dumps(self.metadata).encode('utf-8')).hexdigest()
        self.metadata["canonical_seal"] = seal

        fd, path = tempfile.mkstemp(suffix=".json")
        with os.fdopen(fd, 'w') as f:
            json.dump(self.metadata, f, indent=4)
        return temp_dir, path

if __name__ == "__main__":
    canonizer = Substrato631OpenservGateway()
    temp_dir, report_path = canonizer.generate()
    print("Canonized 631-OPENSERV-GATEWAY into directory: " + temp_dir)
    print("Canonical JSON report: " + report_path)
